const order = $input.first().json;
const currentCount = parseInt($('On form submission').first().json.current_count);

// 1. คำนวณยอดที่ต้องมี (Target)
const targetCount = parseInt(order.start_count) + parseInt(order.quantity);

// 2. คำนวณยอดที่หายไป (Missing)
let missingQty = targetCount - currentCount;

if (missingQty <= 0) {
    return { json: { status: "NO_REFILL_NEEDED", msg: "ยอดครบหรือเกินแล้ว" } };
}

// 3. เลือก Service ที่จะใช้ซ่อม (The Selection Logic)
let serviceToUse = order.service_id; // ค่าเริ่มต้น: ใช้ตัวเดิมซ่อม
let isRefillOrder = true;

// ถ้าบริการเดิมมีขั้นต่ำสูงกว่ายอดที่หาย (เช่น หาย 10 แต่ขั้นต่ำ 100)
// และเรามี Refill Service เตรียมไว้
if (missingQty < order.main_min && order.refill_service_id) {
    serviceToUse = order.refill_service_id; // สลับไปใช้ตัวซ่อมยอดน้อย

    // เช็คอีกทีว่าถึงขั้นต่ำตัวซ่อมไหม (เช่น ตัวซ่อมขั้นต่ำ 5 แต่หาย 10 -> ผ่าน)
    if (missingQty < order.refill_min) {
        // ถ้ายอดน้อยมากๆ จริงๆ อาจต้องปัดขึ้นให้เท่าขั้นต่ำ
        missingQty = order.refill_min; 
    }
} else if (missingQty < order.main_min) {
    // กรณีไม่มีตัวสำรอง แต่ยอดไม่ถึงขั้นต่ำ -> จำใจต้องปัดขึ้นให้เท่าขั้นต่ำของตัวหลัก
    // (ยอมขาดทุนเพิ่มนิดหน่อย เพื่อรักษาลูกค้า)
    missingQty = order.main_min;
}

return {
    json: {
        service_id: serviceToUse,
        link: order.link,
        quantity: missingQty,
        user_id: $input.first().json.user_id,
        action: "CREATE_REPAIR_ORDER",
        original_order_id: order.id,
        price: 0, // ฟรีสำหรับลูกค้า
        remark: `Refill for Order #${order.id} (Missing: ${missingQty})`,
        dependency_order_id: null
    }
};
